54	      });
55	      return {
56	        auth: {
57	          type: "service" as const,
58	          caller: verified.caller,
59	        },
60	        headers: opts.headers,
61	      };
62	    } catch (error) {
63	      log.warn("[trpc] JWT verification error", {
64	        source,
65	        error: error instanceof Error ? error.message : String(error),
66	      });
67	    }
68	  }
69	
70	  // No authentication
71	  log.info("[trpc] platform service request", {
